/* BTSidebar layout — Figma 2346-3623.
   Item-level styles live in internal/BTSidebarItem.css.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

/* ── Root ──────────────────────────────────────────────────────────── */

.bt-sidebar {
  display: flex;
  flex-direction: column;
  /* 16px gap between every top-level section (header, search-row, nav, footer) */
  gap: var(--space-lg);
  /* Fixed open width — min/max enforce it even inside flex parents */
  width: 258px;
  min-width: 258px;
  max-width: 258px;
  height: 100%;
  background: var(--bg-primary);
  border-inline-end: 1px solid var(--border-primary);
  /* Padding: 16px all sides in open state.
     Sections no longer carry their own horizontal padding — aside owns it. */
  padding: var(--space-lg);
  transition: width 0.3s ease, min-width 0.3s ease, max-width 0.3s ease,
              padding 0.3s ease;
  overflow: hidden;
  flex-shrink: 0;
}

.bt-sidebar--collapsed {
  width: 64px;
  min-width: 64px;
  max-width: 64px;
  /* Collapsed: no horizontal padding — items center themselves */
  padding: var(--space-lg) 0;
}

/* ── Header ─────────────────────────────────────────────────────────── */

.bt-sidebar__header {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
  /* margin: sidebar gap: 16px handles section spacing */
}

.bt-sidebar--collapsed .bt-sidebar__header {
  justify-content: center;
  gap: 0;
}

.bt-sidebar__logo {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  object-fit: cover;
  flex-shrink: 0;
}

.bt-sidebar__header-text {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  flex: 1;
  min-width: 0;
  overflow: hidden;
  max-width: 180px;
  transition: opacity 0.2s ease, max-width 0.3s ease, flex 0.3s ease;
}

.bt-sidebar--collapsed .bt-sidebar__header-text {
  opacity: 0;
  max-width: 0;
  flex: 0;
  pointer-events: none;
}

.bt-sidebar__header-title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-sidebar__header-desc {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* ── Search + toggle row ────────────────────────────────────────────── */

.bt-sidebar__search-row {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--space-sm);
  flex-shrink: 0;
  /* padding-bottom: sidebar gap: 16px handles section spacing */
}

.bt-sidebar--collapsed .bt-sidebar__search-row {
  justify-content: center;
}

/* Wrapper gives BTInputSearch flex-1 behaviour */
.bt-sidebar__search-wrapper {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  transition: opacity 0.2s ease, flex 0.3s ease;
}

/* Toggle icon — 16×16 Figma icon inside BTButton icon-only small. */
.bt-sidebar__toggle-icon {
  width: 16px;
  height: 16px;
  display: block;
  pointer-events: none;
  flex-shrink: 0;
}

/* ── Navigation container ────────────────────────────────────────────── */

.bt-sidebar__nav {
  flex: 1;
  overflow-y: auto;
  /* Bleed nav to aside border edges so scrollbar sits flush at aside border,
     not inside the 16px padding area. 16px horizontal padding restores the
     aside content boundary — item backgrounds align with the search input. */
  margin: 0 -16px;
  padding: 0 var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.bt-sidebar__nav--scroll {
  /* Thin scrollbar indicator when hasScroll=true */
}

.bt-sidebar--collapsed .bt-sidebar__nav {
  /* Collapsed aside has padding: 16px 0 (no horizontal) — no negative margin needed */
  margin: 0;
  padding: 0;
  align-items: center;
}

/* Thin scrollbar */
.bt-sidebar__nav::-webkit-scrollbar {
  width: 4px;
}

.bt-sidebar__nav::-webkit-scrollbar-thumb {
  background: var(--border-primary);
  border-radius: var(--radius-xs);
}

.bt-sidebar__nav::-webkit-scrollbar-track {
  background: transparent;
}

/* ── Item group wrapper (holds item row + children) ──────────────────── */

.bt-sidebar__item-group {
  display: flex;
  flex-direction: column;
}

/* BTTooltip wrapper inside sidebar: stretch to fill nav width (overrides inline-flex shrink-wrap) */
.bt-sidebar .bt-tooltip {
  display: flex;
  align-self: stretch;
  min-width: 0;
}

/* Open sidebar: sidebar item must fill the full width of its BTTooltip trigger wrapper.
   Without this, .bt-sidebar-item (display:flex) only takes content width inside
   the flex-row .bt-tooltip container, so hover/active backgrounds don't span the row. */
.bt-sidebar:not(.bt-sidebar--collapsed) .bt-tooltip > .bt-sidebar-item {
  flex: 1;
  min-width: 0;
}

/* ── Divider ─────────────────────────────────────────────────────────── */

.bt-sidebar__divider {
  height: 1px;
  background: var(--border-primary);
}

/* Collapsed: show a short centred line (32 px) instead of the full-width rule */
.bt-sidebar--collapsed .bt-sidebar__divider {
  width: 32px;
  align-self: center;
}

/* ── Sub Title (section label) ───────────────────────────────────────── */

.bt-sidebar__subtitle {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding-block: 8px;
  padding-inline-end: 4px;
  padding-inline-start: 0; /* nav already gives 16px from border; no extra start indent needed */
  white-space: nowrap;
  overflow: hidden;
  max-height: 36px;
  transition: opacity 0.25s ease, max-height 0.3s ease, padding-block 0.3s ease;
}

.bt-sidebar--collapsed .bt-sidebar__subtitle {
  opacity: 0;
  max-height: 0;
  padding-block: 0;
  pointer-events: none;
}

/* ── Children expand/collapse container ──────────────────────────────── */

.bt-sidebar__children {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  max-height: 0;
  gap: var(--space-lg);
  padding-top: 0;
  transition: max-height 0.25s ease, padding-top 0.25s ease;
}

.bt-sidebar__item-group--expanded > .bt-sidebar__children {
  max-height: 2000px;
  padding-top: var(--space-lg);
}

/* Collapsed: force all children shut */
.bt-sidebar--collapsed .bt-sidebar__children {
  max-height: 0;
  padding-top: 0;
}

/* ── Footer ──────────────────────────────────────────────────────────── */

.bt-sidebar__footer {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
  /* padding-top: sidebar gap: 16px handles section spacing */
}

.bt-sidebar--collapsed .bt-sidebar__footer {
  justify-content: center;
  gap: 0;
}

/* BTAvatar (size="sm") handles its own 32×32 circle — no extra styles needed here. */

.bt-sidebar__footer-text {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  flex: 1;
  overflow: hidden;
  max-width: 160px;
  transition: opacity 0.2s ease, max-width 0.3s ease;
}

.bt-sidebar--collapsed .bt-sidebar__footer-text {
  opacity: 0;
  max-width: 0;
  pointer-events: none;
}

.bt-sidebar__footer-name {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-sidebar__footer-email {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/**
 * BTSidebar — collapsible navigation sidebar for desktop layouts.
 * Figma: node 2346-3623 (D-Sidebar).
 *
 * Composes:
 *   - BTAvatar       (footer user avatar, size="sm")
 *   - BTButton       (toggle button, secondary-light icon-only)
 *   - BTInputSearch  (search row, when searchValue prop is provided)
 *   - BTSidebarItem  (each interactive nav row)
 *
 * @example
 * ```tsx
 * const [open, setOpen] = useState(true);
 * <BTSidebar
 *   open={open}
 *   header={{
 *     logo: <img src="/logo.svg" className="bt-sidebar__logo" alt="App" />,
 *     title: 'Workspace',
 *     description: 'Team',
 *   }}
 *   items={navItems}
 *   onToggle={() => setOpen(v => !v)}
 *   onItemClick={handleNav}
 * />
 * ```
 */
import { useState, useEffect, useCallback } from 'react';
import './BTSidebar.css';
import { BTButton } from '../button/BTButton.js';
import { BTInputSearch } from '../input-search/BTInputSearch.js';
import { BTSidebarItem } from './internal/BTSidebarItem.js';
import { BTSidebarContext } from './internal/BTSidebarContext.js';
import type { BTSidebarProps, BTSidebarNavItem } from './BTSidebar.types.js';

// ── Root component ───────────────────────────────────────────────────────────

export function BTSidebar({
  open = true,
  hasScroll: _hasScroll = false,
  header,
  items = [],
  footer,
  searchValue,
  initialExpandedIds = [],
  onToggle,
  onSearch,
  onItemClick,
}: BTSidebarProps) {
  // ── Expand/collapse tracking ───────────────────────────────────────────────
  // Seed with initialExpandedIds so demos can pre-open items.
  const [expandedIds, setExpandedIds] = useState<Set<string>>(
    () => new Set(initialExpandedIds),
  );

  // When the sidebar collapses, close all expanded groups so the children
  // container (max-height animated) snaps shut — prevents phantom vertical space.
  useEffect(() => {
    if (!open) {
      setExpandedIds(new Set());
    }
  }, [open]);

  const isExpanded = useCallback(
    (id: string) => expandedIds.has(id),
    [expandedIds],
  );

  const handleItemClick = useCallback(
    (item: BTSidebarNavItem) => {
      // Toggle expand if item has children
      if (item.children?.length) {
        setExpandedIds(prev => {
          const next = new Set(prev);
          if (next.has(item.id)) {
            next.delete(item.id);
          } else {
            next.add(item.id);
          }
          return next;
        });
      }
      onItemClick?.(item);
    },
    [onItemClick],
  );

  const hasSearch = searchValue !== undefined;

  const rootClass = ['bt-sidebar', !open ? 'bt-sidebar--collapsed' : '', !header ? 'bt-sidebar--no-header' : '']
    .filter(Boolean)
    .join(' ');

  return (
    <BTSidebarContext.Provider value={{ open }}>
      <aside className={rootClass} aria-expanded={open}>

        {/* ── Header ─────────────────────────────────────────────────── */}
        {header && (
          <div className="bt-sidebar__header">
            {/* Logo — any ReactNode: img, svg, custom icon component, etc. */}
            {header.logo}
            {(header.title || header.description) && (
              <div className="bt-sidebar__header-text">
                {header.title && (
                  <span className="bt-sidebar__header-title">{header.title}</span>
                )}
                {header.description && (
                  <span className="bt-sidebar__header-desc">{header.description}</span>
                )}
              </div>
            )}
          </div>
        )}

        {/* ── Search + toggle row ─────────────────────────────────────── */}
        <div className="bt-sidebar__search-row">
          {/* BTInputSearch: flex-1, visible only when open + hasSearch */}
          {open && hasSearch && (
            <div className="bt-sidebar__search-wrapper">
              <BTInputSearch
                value={searchValue ?? ''}
                onChange={v => onSearch?.(v)}
                onSearch={q => onSearch?.(q)}
                placeholder="Search..."
              />
            </div>
          )}

          {/* Toggle button — BTButton secondary-light icon-only.
              Open → |← (horizontal_align_left, minimize)
              Collapsed → →| (horizontal_align_right, expand) */}
          <BTButton
            iconOnly
            variant="secondary-light"
            size={open ? 'default' : 'small'}
            aria-label={open ? 'Collapse sidebar' : 'Expand sidebar'}
            onClick={onToggle}
          >
            {open ? (
              /* |← minimize icon (Figma: horizontal_align_left, node 2217:15706) */
              <svg
                className="bt-sidebar__toggle-icon"
                viewBox="0 0 12 10.6667"
                fill="none"
                aria-hidden="true"
              >
                <path d="M0.191667 10.475C0.0638889 10.3472 0 10.1889 0 10V0.666667C0 0.477778 0.0638889 0.319444 0.191667 0.191667C0.319444 0.0638889 0.477778 0 0.666667 0C0.855556 0 1.01389 0.0638889 1.14167 0.191667C1.26944 0.319444 1.33333 0.477778 1.33333 0.666667V10C1.33333 10.1889 1.26944 10.3472 1.14167 10.475C1.01389 10.6028 0.855556 10.6667 0.666667 10.6667C0.477778 10.6667 0.319444 10.6028 0.191667 10.475ZM5.2 6L6.46667 7.26667C6.58889 7.38889 6.65 7.54444 6.65 7.73333C6.65 7.92222 6.58889 8.07778 6.46667 8.2C6.34444 8.32222 6.18889 8.38333 6 8.38333C5.81111 8.38333 5.65556 8.32222 5.53333 8.2L3.13333 5.8C3.06667 5.73333 3.01944 5.66111 2.99167 5.58333C2.96389 5.50556 2.95 5.42222 2.95 5.33333C2.95 5.24444 2.96389 5.16111 2.99167 5.08333C3.01944 5.00556 3.06667 4.93333 3.13333 4.86667L5.53333 2.46667C5.65556 2.34444 5.81111 2.28333 6 2.28333C6.18889 2.28333 6.34444 2.34444 6.46667 2.46667C6.58889 2.58889 6.65 2.74444 6.65 2.93333C6.65 3.12222 6.58889 3.27778 6.46667 3.4L5.2 4.66667H11.3333C11.5222 4.66667 11.6806 4.73056 11.8083 4.85833C11.9361 4.98611 12 5.14444 12 5.33333C12 5.52222 11.9361 5.68056 11.8083 5.80833C11.6806 5.93611 11.5222 6 11.3333 6H5.2Z" fill="currentColor" />
              </svg>
            ) : (
              /* →| expand icon (Figma: horizontal_align_right, node 2346:2654) */
              <svg
                className="bt-sidebar__toggle-icon"
                viewBox="0 0 12 10.6667"
                fill="none"
                aria-hidden="true"
              >
                <path d="M10.8583 10.475C10.7306 10.3472 10.6667 10.1889 10.6667 10V0.666667C10.6667 0.477778 10.7306 0.319444 10.8583 0.191667C10.9861 0.0638889 11.1444 0 11.3333 0C11.5222 0 11.6806 0.0638889 11.8083 0.191667C11.9361 0.319444 12 0.477778 12 0.666667V10C12 10.1889 11.9361 10.3472 11.8083 10.475C11.6806 10.6028 11.5222 10.6667 11.3333 10.6667C11.1444 10.6667 10.9861 10.6028 10.8583 10.475ZM6.8 6H0.666667C0.477778 6 0.319444 5.93611 0.191667 5.80833C0.0638889 5.68056 0 5.52222 0 5.33333C0 5.14444 0.0638889 4.98611 0.191667 4.85833C0.319444 4.73056 0.477778 4.66667 0.666667 4.66667H6.8L5.53333 3.4C5.41111 3.27778 5.35 3.12222 5.35 2.93333C5.35 2.74444 5.41111 2.58889 5.53333 2.46667C5.65556 2.34444 5.81111 2.28333 6 2.28333C6.18889 2.28333 6.34444 2.34444 6.46667 2.46667L8.86667 4.86667C8.93333 4.93333 8.98056 5.00556 9.00833 5.08333C9.03611 5.16111 9.05 5.24444 9.05 5.33333C9.05 5.42222 9.03611 5.50556 9.00833 5.58333C8.98056 5.66111 8.93333 5.73333 8.86667 5.8L6.46667 8.2C6.34444 8.32222 6.18889 8.38333 6 8.38333C5.81111 8.38333 5.65556 8.32222 5.53333 8.2C5.41111 8.07778 5.35 7.92222 5.35 7.73333C5.35 7.54444 5.41111 7.38889 5.53333 7.26667L6.8 6Z" fill="currentColor" />
              </svg>
            )}
          </BTButton>
        </div>

        {/* ── Navigation items ────────────────────────────────────────── */}
        <nav
          className={`bt-sidebar__nav${_hasScroll ? ' bt-sidebar__nav--scroll' : ''}`}
          aria-label="Navigation"
        >
          {items.map((item) => {

            /* Divider: always visible — both open and collapsed states */
            if (item.type === 'Divider') {
              return <div key={item.id} className="bt-sidebar__divider" role="separator" />;
            }

            /* Sub Title: visible only when open — hidden when collapsed */
            if (item.type === 'Sub Title') {
              return open ? (
                <div key={item.id} className="bt-sidebar__subtitle">
                  {item.label}
                </div>
              ) : null;
            }

            /* Main item: icon row, optionally expandable */
            if (item.type === 'Main') {
              const expanded = isExpanded(item.id);
              return (
                <div
                  key={item.id}
                  className={`bt-sidebar__item-group${expanded ? ' bt-sidebar__item-group--expanded' : ''}`}
                >
                  <BTSidebarItem
                    item={item}
                    expanded={expanded}
                    icon={item.icon ?? undefined}
                    onClick={handleItemClick}
                  />

                  {/* Level-2 children (Submenu items) */}
                  {!!item.children?.length && (
                    <div className="bt-sidebar__children">
                      {item.children.map((sub) => {
                        if (sub.type === 'Submenu') {
                          const subExpanded = isExpanded(sub.id);
                          return (
                            <div
                              key={sub.id}
                              className={`bt-sidebar__item-group${subExpanded ? ' bt-sidebar__item-group--expanded' : ''}`}
                            >
                              <BTSidebarItem
                                item={sub}
                                expanded={subExpanded}
                                icon={<span className="bt-sidebar-item__dot" aria-hidden="true" />}
                                onClick={handleItemClick}
                              />

                              {/* Level-3 children (Sub Submenu items) */}
                              {!!sub.children?.length && (
                                <div className="bt-sidebar__children">
                                  {sub.children.map((subsub) => (
                                    <BTSidebarItem
                                      key={subsub.id}
                                      item={subsub}
                                      icon={<span className="bt-sidebar-item__dot" aria-hidden="true" />}
                                      onClick={handleItemClick}
                                    />
                                  ))}
                                </div>
                              )}
                            </div>
                          );
                        }

                        /* Flat Sub Submenu directly under Main (uncommon but valid) */
                        return (
                          <BTSidebarItem
                            key={sub.id}
                            item={sub}
                            icon={<span className="bt-sidebar-item__dot" aria-hidden="true" />}
                            onClick={handleItemClick}
                          />
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            }

            /* Flat Submenu / Sub Submenu at root level (graceful fallback) —
               at this point item.type is narrowed to Submenu | Sub Submenu, so always use dot */
            return (
              <BTSidebarItem
                key={item.id}
                item={item}
                icon={<span className="bt-sidebar-item__dot" aria-hidden="true" />}
                onClick={handleItemClick}
              />
            );
          })}
        </nav>

        {/* ── Footer — accepts any ReactNode ─────────────────────────── */}
        {footer && (
          <div className="bt-sidebar__footer">
            {footer}
          </div>
        )}

      </aside>
    </BTSidebarContext.Provider>
  );
}

BTSidebar.displayName = 'BTSidebar';

import type { ReactNode } from 'react';
import type { BTAvatarItem } from '../avatar/BTAvatar.types.js';

export type { BTAvatarItem };

export type BTSidebarItemType = 'Main' | 'Submenu' | 'Sub Submenu' | 'Sub Title' | 'Divider';

export interface BTSidebarNavItem {
  /** Unique identifier for the item. */
  id: string;
  /** Layout / visual type. */
  type: BTSidebarItemType;
  /** Display label — unused for Divider. */
  label?: string;
  /**
   * Icon for Main items — any ReactNode (img, svg, icon component, etc.).
   * Rendered as-is inside the icon slot area of the sidebar item row.
   * Ignored for Submenu / Sub Submenu (dot used instead).
   *
   * @example
   * ```tsx
   * icon: <img src="/icons/home.svg" className="bt-sidebar-item__icon-img" alt="" />
   * ```
   */
  icon?: ReactNode;
  /** Whether this item is the currently selected / active page. */
  active?: boolean;
  /** Non-interactive item (visually dimmed, no click). */
  disabled?: boolean;
  /** Child items: Main → Submenu → Sub Submenu. */
  children?: BTSidebarNavItem[];
}

/**
 * Sidebar header data — title, description, and logo.
 * The `logo` field accepts any ReactNode (img, svg, icon component, etc.):
 *
 * ```tsx
 * header={{
 *   logo: <img src="/logo.svg" className="bt-sidebar__logo" alt="App" />,
 *   title: 'App',
 *   description: 'Workspace',
 * }}
 * ```
 */
export interface BTSidebarHeader {
  /** Logo element — any ReactNode rendered in the header. */
  logo?: ReactNode;
  /** Application or workspace title (bold 14 px). */
  title?: string;
  /** Subtitle / description line (12 px text-secondary). */
  description?: string;
}

export interface BTSidebarFooterUser {
  /**
   * Avatar payload passed directly to BTAvatar.
   * Contains: `name` (for initials fallback), optional `imageUrl`, optional `color`.
   * When omitted, BTAvatar renders the empty/person-icon state.
   */
  item?: BTAvatarItem;
  /** User email address (12 px text-secondary). */
  email?: string;
}

export interface BTSidebarProps {
  /** Expanded (258 px) when true, collapsed (64 px) when false. */
  open?: boolean;
  /** Show scrollbar in the nav area. */
  hasScroll?: boolean;
  /** Header logo + title + description. */
  header?: BTSidebarHeader;
  /** Navigation item tree (Main → Submenu → Sub Submenu). */
  items?: BTSidebarNavItem[];
  /**
   * Footer content — accepts any ReactNode.
   * Rendered inside `.bt-sidebar__footer` which handles layout and collapsed state.
   * Use `bt-sidebar__footer-text`, `bt-sidebar__footer-name`, `bt-sidebar__footer-email`
   * CSS classes for the standard avatar + name/email layout.
   */
  footer?: ReactNode;
  /** Controlled search input value (omit to hide the search bar). */
  searchValue?: string;
  /**
   * Item IDs that should be expanded on first render.
   * Useful for demos and deep-link navigation.
   */
  initialExpandedIds?: string[];
  /** Called when the toggle button is clicked. */
  onToggle?: () => void;
  /** Called on search input change. */
  onSearch?: (value: string) => void;
  /** Called when any nav item is clicked. */
  onItemClick?: (item: BTSidebarNavItem) => void;
}

import { createContext, useContext } from 'react';

/**
 * Context provided by BTSidebar to all descendant BTSidebarItem components.
 * Allows items to reactively respond to the sidebar's open/collapsed state
 * without needing an explicit prop at every level.
 */
export interface BTSidebarContextValue {
  /** Whether the sidebar is in expanded (true) or icon-rail (false) state. */
  open: boolean;
}

export const BTSidebarContext = createContext<BTSidebarContextValue>({ open: true });

export function useBTSidebarContext(): BTSidebarContextValue {
  return useContext(BTSidebarContext);
}

/* BTSidebarItem — Figma 159-1729.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

/* ── Base row ───────────────────────────────────────────────────────── */

.bt-sidebar-item {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  border-radius: var(--radius-sm);
  cursor: pointer;
  user-select: none;
  transition: background 0.15s;
  position: relative;
}

/* ── Type-specific padding ──────────────────────────────────────────── */

/* Main: p-8px (all sides equal) */
.bt-sidebar-item--main {
  padding: var(--space-sm);
}

/* Submenu: indented left side */
.bt-sidebar-item--submenu {
  padding: var(--space-sm);
}

/* Sub Submenu: deeper indent — fixed, no shift on hover/disabled */
.bt-sidebar-item--sub-submenu {
  padding: var(--space-sm) var(--space-sm) var(--space-sm) var(--space-xl);
}

/* ── Interactive states ─────────────────────────────────────────────── */

.bt-sidebar-item:hover:not(.bt-sidebar-item--active):not(.bt-sidebar-item--disabled) {
  background: var(--bg-secondary);
}

.bt-sidebar-item--active {
  background: var(--color-brand-primary-subtle);
}

.bt-sidebar-item--disabled {
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Collapsed sidebar: 32×32 icon-only pill, hide submenu rows ─────── */

.bt-sidebar-item--collapsed.bt-sidebar-item--main {
  justify-content: center;
  align-items: center;
  width: 32px;
  height: 32px;
  min-height: 32px;
  padding: var(--space-sm);
  gap: 0; /* suppress gap so label (0px) doesn't push icon off-center */
  align-self: center; /* center within the flex-column sidebar nav */
}

.bt-sidebar-item--collapsed.bt-sidebar-item--submenu,
.bt-sidebar-item--collapsed.bt-sidebar-item--sub-submenu {
  display: none;
}

/* ── Icon (Main items) — rendered as CSS mask so color is fully state-driven ── */

.bt-sidebar-item__icon {
  /* Mask-based icon: background-color = the visible icon color.
     The SVG data-URI is used as a shape mask — its own stroke/fill colors are ignored.
     Only the alpha channel of the SVG determines which pixels are colored. */
  display: block;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  background-color: var(--text-primary);   /* default: dark text color */
  -webkit-mask-size: contain;
  mask-size: contain;
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-position: center;
  mask-position: center;
  transition: background-color 0.15s;
}

/* Active → brand primary */
.bt-sidebar-item--active .bt-sidebar-item__icon {
  background-color: var(--color-brand-primary);
}

/* Hover (non-active, non-disabled) → brand primary */
.bt-sidebar-item:hover:not(.bt-sidebar-item--active):not(.bt-sidebar-item--disabled)
  .bt-sidebar-item__icon {
  background-color: var(--color-brand-primary);
}

/* Disabled → disabled token */
.bt-sidebar-item--disabled .bt-sidebar-item__icon {
  background-color: var(--text-disabled);
}

/* ── Dot indicator (Submenu / Sub Submenu) ──────────────────────────── */

.bt-sidebar-item__dot {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.bt-sidebar-item__dot::after {
  content: '';
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-secondary);
  transition: background 0.15s;
}

/* Active dot */
.bt-sidebar-item--active .bt-sidebar-item__dot::after {
  background: var(--color-brand-primary);
}

/* Hover dot */
.bt-sidebar-item:hover:not(.bt-sidebar-item--disabled) .bt-sidebar-item__dot::after {
  background: var(--color-brand-primary);
}

/* Disabled dot */
.bt-sidebar-item--disabled .bt-sidebar-item__dot::after {
  background: var(--text-disabled);
}

/* ── Label ──────────────────────────────────────────────────────────── */

.bt-sidebar-item__label {
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  transition: opacity 0.2s ease, max-width 0.3s ease, color 0.15s;
}

/* Submenu / Sub Submenu: smaller text */
.bt-sidebar-item--submenu .bt-sidebar-item__label,
.bt-sidebar-item--sub-submenu .bt-sidebar-item__label {
  font-size: var(--typography-font-size-xs);
  line-height: var(--typography-line-height-xs);
}

/* Active label: brand primary, bolder weight */
.bt-sidebar-item--active .bt-sidebar-item__label {
  color: var(--color-brand-primary);
  font-weight: 700;
}

/* Active Submenu / Sub Submenu: 600 weight */
.bt-sidebar-item--active.bt-sidebar-item--submenu .bt-sidebar-item__label,
.bt-sidebar-item--active.bt-sidebar-item--sub-submenu .bt-sidebar-item__label {
  font-weight: 600;
}

/* Disabled label */
.bt-sidebar-item--disabled .bt-sidebar-item__label {
  color: var(--text-disabled);
}

/* Hover label (non-active, non-disabled) */
.bt-sidebar-item:hover:not(.bt-sidebar-item--active):not(.bt-sidebar-item--disabled)
  .bt-sidebar-item__label {
  color: var(--color-brand-primary);
}

/* Collapsed: hide labels */
.bt-sidebar-item--collapsed .bt-sidebar-item__label {
  opacity: 0;
  max-width: 0;
  pointer-events: none;
  overflow: hidden;
}

/* ── Chevron ────────────────────────────────────────────────────────── */

.bt-sidebar-item__chevron {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  color: var(--text-secondary);
  transition: transform 0.2s ease, opacity 0.2s ease;
}

/* Expanded: chevron rotates 90° */
.bt-sidebar-item--expanded .bt-sidebar-item__chevron {
  transform: rotate(90deg);
}

/* Collapsed: hide chevron */
.bt-sidebar-item--collapsed .bt-sidebar-item__chevron {
  opacity: 0;
  max-width: 0;
  overflow: hidden;
}

/**
 * BTSidebarItem — single interactive nav row inside BTSidebar.
 * Figma: node 159-1729.
 *
 * Handles types: Main, Submenu, Sub Submenu.
 * Sub Title and Divider are rendered by the parent BTSidebar.
 *
 * @example
 * ```tsx
 * <BTSidebarItem
 *   item={{ id: 'home', type: 'Main', label: 'Home', active: true }}
 *   icon={<span className="bt-sidebar-item__icon" style={iconMaskStyle(src)} />}
 *   onClick={onItemClick}
 * />
 * ```
 */
import type { KeyboardEvent, ReactNode } from 'react';
import { useCallback } from 'react';
import './BTSidebarItem.css';
import { BTTooltip } from '../../tooltip/BTTooltip.js';
import type { BTSidebarNavItem } from '../BTSidebar.types.js';
import { useBTSidebarContext } from './BTSidebarContext.js';

interface BTSidebarItemProps {
  /** The navigation item data. */
  item: BTSidebarNavItem;
  /** Whether this item's submenu children are currently expanded. */
  expanded?: boolean;
  /** Icon or dot element — omit for no leading indicator. */
  icon?: ReactNode;
  /** Called when the item is clicked (disabled items are silently ignored). */
  onClick?: (item: BTSidebarNavItem) => void;
}

const TYPE_CLASS: Record<string, string> = {
  Main: 'bt-sidebar-item--main',
  Submenu: 'bt-sidebar-item--submenu',
  'Sub Submenu': 'bt-sidebar-item--sub-submenu',
};

export function BTSidebarItem({ item, expanded = false, icon, onClick }: BTSidebarItemProps) {
  const { open: sidebarOpen } = useBTSidebarContext();

  const handleClick = useCallback(() => {
    if (item.disabled) return;
    onClick?.(item);
  }, [item, onClick]);

  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleClick();
      }
    },
    [handleClick],
  );

  // Show chevron when item has children, EXCEPT for Main + disabled (Figma 159-1729)
  const showChevron = !!item.children?.length && !(item.type === 'Main' && item.disabled);

  // Tooltip: only for Main items when sidebar is collapsed
  const tooltipDisabled = sidebarOpen || item.type !== 'Main' || !item.label;

  const cls = [
    'bt-sidebar-item',
    TYPE_CLASS[item.type] ?? 'bt-sidebar-item--main',
    item.active ? 'bt-sidebar-item--active' : '',
    item.disabled ? 'bt-sidebar-item--disabled' : '',
    expanded ? 'bt-sidebar-item--expanded' : '',
    !sidebarOpen ? 'bt-sidebar-item--collapsed' : '',
  ].filter(Boolean).join(' ');

  return (
    <BTTooltip
      text={item.label}
      position="right"
      disabled={tooltipDisabled}
      showDelay={200}
      compact
    >
      <div
        className={cls}
        role="button"
        tabIndex={item.disabled ? -1 : 0}
        aria-disabled={item.disabled || undefined}
        aria-expanded={item.children?.length ? expanded : undefined}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
      >
        {/* Left icon / dot slot */}
        {icon}

        {/* Label (hidden via CSS in collapsed mode) */}
        <span className="bt-sidebar-item__label">{item.label}</span>

        {/* Chevron — data-driven; Main+disabled has none (Figma spec) */}
        {showChevron && (
          <svg
            className="bt-sidebar-item__chevron"
            viewBox="0 0 16 16"
            fill="none"
            aria-hidden="true"
          >
            <path
              d="M6 4L10 8L6 12"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        )}
      </div>
    </BTTooltip>
  );
}

BTSidebarItem.displayName = 'BTSidebarItem';
